"use client";

import { useEffect, useState } from "react";
import axios from "axios";
import { signOut } from "next-auth/react";
import { useRouter } from "next/navigation";

export default function Dashboard() {
  const [stats, setStats] = useState<any>(null);
  const router = useRouter();

  useEffect(() => {
    axios.get("/api/leetcode-stats").then((res) => {
      if (res.data.success) {
        setStats(res.data.data);
      }
    });
  }, []);

  const handleLogout = async () => {
    await signOut({ callbackUrl: "/" });
  };

  if (!stats)
    return (
      <div className="min-h-screen flex items-center justify-center bg-[#0f0f0f] text-white">
        <div className="text-lg font-medium">Loading Dashboard...</div>
      </div>
    );

  const total = stats.easy + stats.medium + stats.hard;

  const easyPercent = (stats.easy / total) * 100;
  const mediumPercent = (stats.medium / total) * 100;
  const hardPercent = (stats.hard / total) * 100;

  const radius = 80;
  const circumference = 2 * Math.PI * radius;

  const easyStroke = (easyPercent / 100) * circumference;
  const mediumStroke = (mediumPercent / 100) * circumference;
  const hardStroke = (hardPercent / 100) * circumference;

  return (
    <div className="min-h-screen bg-gradient-to-b from-[#0f0f0f] to-[#1a1a1a] px-6 sm:px-10 py-10 text-white">

      {/* HEADER */}
      <div className="relative flex justify-center mb-12">
        <h1 className="text-4xl sm:text-5xl font-semibold text-center">
          <span className="font-extrabold bg-gradient-to-r from-purple-400 to-blue-400 bg-clip-text text-transparent">
            LeetOtracker
          </span>{" "}
          Dashboard
        </h1>

        <button
          onClick={handleLogout}
          className="absolute right-0 top-0 bg-red-600 hover:bg-red-700 px-4 py-2 rounded-lg text-sm font-medium transition"
        >
          Logout
        </button>
      </div>

      {/* PROFILE CARD */}
      <div className="bg-[#1c1c1c] shadow-lg rounded-2xl p-6 mb-10 flex flex-col sm:flex-row items-center justify-between gap-6">

        <div>
          <h2 className="text-2xl font-semibold">
            {stats.username}
          </h2>
          <p className="text-gray-400 mt-1">
            Rank: {stats.ranking}
          </p>
          <p className="text-green-400 font-medium mt-2">
            {stats.totalSolved} Problems Solved
          </p>
        </div>

        <a
          href={`https://leetcode.com/${stats.username}`}
          target="_blank"
          className="bg-green-600 hover:bg-green-700 px-5 py-2 rounded-lg transition"
        >
          View LeetCode Profile
        </a>
      </div>

      {/* DIFFICULTY RING */}
      <div className="bg-[#1c1c1c] shadow-lg rounded-2xl p-10 flex justify-center">

        <div className="relative w-56 h-56">

          <svg
            className="w-full h-full rotate-[-90deg]"
            viewBox="0 0 200 200"
          >
            {/* Background */}
            <circle
              cx="100"
              cy="100"
              r={radius}
              stroke="#2a2a2a"
              strokeWidth="18"
              fill="none"
            />

            {/* Easy */}
            <circle
              cx="100"
              cy="100"
              r={radius}
              stroke="#22c55e"
              strokeWidth="18"
              fill="none"
              strokeDasharray={`${easyStroke} ${circumference}`}
              strokeLinecap="round"
              className="transition-all duration-1000"
            />

            {/* Medium */}
            <circle
              cx="100"
              cy="100"
              r={radius}
              stroke="#eab308"
              strokeWidth="18"
              fill="none"
              strokeDasharray={`${mediumStroke} ${circumference}`}
              strokeDashoffset={-easyStroke}
              strokeLinecap="round"
              className="transition-all duration-1000 delay-200"
            />

            {/* Hard */}
            <circle
              cx="100"
              cy="100"
              r={radius}
              stroke="#ef4444"
              strokeWidth="18"
              fill="none"
              strokeDasharray={`${hardStroke} ${circumference}`}
              strokeDashoffset={-(easyStroke + mediumStroke)}
              strokeLinecap="round"
              className="transition-all duration-1000 delay-300"
            />
          </svg>

          {/* CENTER TEXT */}
          <div className="absolute inset-0 flex flex-col items-center justify-center">
            <span className="text-3xl font-bold">
              {stats.totalSolved}
            </span>
            <span className="text-gray-400 text-sm mt-1">
              Total Solved
            </span>
          </div>
        </div>

      </div>

      {/* STATS GRID */}
      <div className="grid grid-cols-2 sm:grid-cols-4 gap-6 mt-10">

        <StatCard title="Easy" value={stats.easy} color="text-green-400" />
        <StatCard title="Medium" value={stats.medium} color="text-yellow-400" />
        <StatCard title="Hard" value={stats.hard} color="text-red-400" />
        <StatCard title="Ranking" value={stats.ranking} color="text-blue-400" />

      </div>

    </div>
  );
}

function StatCard({ title, value, color }: any) {
  return (
    <div className="bg-[#1c1c1c] rounded-xl p-6 text-center hover:bg-[#252525] transition">
      <h3 className="text-gray-400 text-sm">{title}</h3>
      <p className={`text-2xl font-bold mt-2 ${color}`}>
        {value}
      </p>
    </div>
  );
}
